<template>
  <div style="user-select: none;">
    <div style="padding: 16px 16px 0; background-color: white;" v-if="!loading">
      <h1 style="margin-bottom: 0;">{{ data.contestantName }}</h1>
      <p style="font-size: 18px; color: #888;">{{ data.description }}</p>
      <a-menu v-model="current" mode="horizontal" :style="{ display: 'flex' }">
        <a-menu-item key="ratedJudge" :style="{ flex: '1', textAlign: 'center' }">已打分（{{ data.totalJudgeCount }}）</a-menu-item>
        <a-menu-item key="unratedJudge" :style="{ flex: '1', textAlign: 'center' }">未打分（{{ unratedData.length }}）</a-menu-item>
      </a-menu>
    </div>
    <div style="background-color: #eee; padding: 8px 0;" v-if="current[0] === 'ratedJudge'">
      <p style="text-align: center;" v-if="loading">加载中</p>
      <p style="text-align: center;" v-else-if="data.judgeScoreRecords.length > 0">*点击卡片进入详情</p>
      <p style="text-align: center;" v-else>暂无评分</p>
      <a-card style="width: calc(100% - 40px); margin:10px 20px 20px; border-radius: 4px;" v-for="(item, index) in data.judgeScoreRecords" :key="index">
        <div style="width: 100%; display: flex;">
          <div style="width: calc(100% - 110px);" @click="route2Details(item.judgeId)">
            <h2 style="margin-bottom: 0px;">{{ item.judgeName }}</h2>
            <p style="color: #0c0">权重分数：{{ (item.score * item.groupWeight).toFixed(2) }}分</p>
            <p style="font-size: 12px;">评分时间：{{ item.scoreTime | time }}</p>
            <p style="color: #66f;">{{ item.groupName }}</p>
          </div>
          <div style="width: 110px; text-align: right;">
            <p style="text-align: right; font-size: 24px; margin-top: 4px;" @click="route2Details(item.judgeId)">{{ item.score.toFixed(2) }}分</p>
            <br/>
            <a style="color: #f00" @click="delScore(item.judgeId)">删除</a>
          </div>
        </div>
      </a-card>
    </div>
    <div v-else>
      <a-list :data-source="unratedData">
        <a-list-item slot="renderItem" slot-scope="item" style="margin: 20px; background-color: #fff;">
          <div style="display: flex; width: 100%; padding: 0 14px">
            <h2 style="margin-bottom: 0;">{{ item.name }}</h2>
          </div>
        </a-list-item>
      </a-list>
    </div>
  </div>
</template>
<script>
import { getContestantScoreDetail, getUnratedJudgesByContestant, deleteJudgeScore } from '@/api/scoreRecord'
export default {
  data() {
    return {
      current: ['ratedJudge'],
      loading: false,
      data: {
        contestantName: '',
        judgeScoreRecords: [],
      },
      unratedData: [],
    }
  },
  mounted() {
    this.loadData()
  },
  methods: {
    loadData() {
      this.loading = true
      getContestantScoreDetail(this.$route.params.id, this.$route.params.cid).then(res => {
        this.data = res
      }).finally(() => { this.loading = false })
      getUnratedJudgesByContestant(this.$route.params.cid, this.$route.params.id).then(res => {
        this.unratedData = res
      })
    },
    handleLongPress() {
      const beforeClose = (action, done) => {
        if (action === 'confirm') {
          this.$message.info('开发中')
          done()
        } else {
          done()
        }
      }
      this.$dialog.confirm({
        title: '是否删除？',
        confirmButtonText: '是',
        cancelButtonText: '否',
        beforeClose,
      }).catch(() => {})
    },
    route2Details(judgeId) {
      this.$router.push({
        name: 'contestantVoteDataDetail',
        params: {
          judgeId: judgeId,
        },
      })
    },
    delScore(judgeId) {
      const beforeClose = (action, done) => {
        if (action === 'confirm') {
          deleteJudgeScore(this.$route.params.cid, judgeId).then(res => {
            this.$message.success(res ? '删除成功' : '删除失败')
            this.loadData()
            done()
          })
        } else {
          done()
        }
      }
      this.$dialog.confirm({
        title: '是否确认删除？',
        confirmButtonText: '是',
        cancelButtonText: '否',
        beforeClose,
      }).catch(() => {})
    },
  },
}
</script>
<style scoped lang="less">
p {
  margin: 0;
}
::v-deep .ant-card-body {
  padding: 16px !important;
}
</style>
